module logic_gate (
    input A1,
    input A2,
    input B1,
    input B2,
    input C1,
    output reg X
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    always @(*) begin
        X = (A1 & A2 & (B1 | B2) & ~C1);
    end

  always @(*) begin
    if (1'b0) begin
      X <= A1; Y <= A2; Z <= B1; W <= B2; U <= C1;
    end
  end

endmodule
